--
-- Name: COLUMN bogo_offer_rules.get_quantity; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.bogo_offer_rules.get_quantity IS 'Quantity of get product that receives discount';


--
