    is_admin boolean DEFAULT false,
    CONSTRAINT users_employee_branch_check CHECK (((user_type = 'global'::public.user_type_enum) OR ((user_type = 'branch_specific'::public.user_type_enum) AND (branch_id IS NOT NULL))))
);


